import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"WAL, checkpoints y recuperacion","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/postgresql/13-wal-checkpoints-y-recuperacion.md","filePath":"bases-de-datos/postgresql/13-wal-checkpoints-y-recuperacion.md","lastUpdated":1782521464000}'),t={name:"bases-de-datos/postgresql/13-wal-checkpoints-y-recuperacion.md"};function r(c,a,p,o,l,h){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="wal-checkpoints-y-recuperacion" tabindex="-1">WAL, checkpoints y recuperacion <a class="header-anchor" href="#wal-checkpoints-y-recuperacion" aria-label="Permalink to &quot;WAL, checkpoints y recuperacion&quot;">​</a></h1><p>WAL significa Write-Ahead Log. PostgreSQL escribe cambios en WAL antes de considerar confirmada una transaccion. Esto permite recuperar consistencia despues de un fallo.</p><h2 id="flujo-de-escritura" tabindex="-1">Flujo de escritura <a class="header-anchor" href="#flujo-de-escritura" aria-label="Permalink to &quot;Flujo de escritura&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant C as Cliente</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant E as Executor</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant W as WAL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant D as Data files</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C-&gt;&gt;E: COMMIT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E-&gt;&gt;W: escribe registro WAL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  W--&gt;&gt;E: fsync segun configuracion</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E--&gt;&gt;C: commit confirmado</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E-&gt;&gt;D: paginas de datos se escriben despues</span></span></code></pre></div><h2 id="por-que-wal-importa" tabindex="-1">Por que WAL importa <a class="header-anchor" href="#por-que-wal-importa" aria-label="Permalink to &quot;Por que WAL importa&quot;">​</a></h2><p>WAL permite:</p><ul><li>Crash recovery.</li><li>Replicacion fisica.</li><li>Point-in-time recovery.</li><li>Backups consistentes.</li></ul><h2 id="checkpoints" tabindex="-1">Checkpoints <a class="header-anchor" href="#checkpoints" aria-label="Permalink to &quot;Checkpoints&quot;">​</a></h2><p>Un checkpoint marca un punto donde PostgreSQL asegura que muchas paginas sucias ya fueron escritas a disco.</p><p>Demasiados checkpoints pueden generar I/O intenso. Checkpoints muy separados pueden aumentar tiempo de recuperacion.</p><h2 id="archiving" tabindex="-1">Archiving <a class="header-anchor" href="#archiving" aria-label="Permalink to &quot;Archiving&quot;">​</a></h2><p>Para recuperacion a punto en el tiempo necesitas archivar WAL:</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>archive_mode = on</span></span>
<span class="line"><span>archive_command = &#39;cp %p /backups/wal/%f&#39;</span></span></code></pre></div><p>En produccion real conviene usar herramientas robustas como pgBackRest, Barman o soluciones gestionadas.</p><h2 id="replicacion" tabindex="-1">Replicacion <a class="header-anchor" href="#replicacion" aria-label="Permalink to &quot;Replicacion&quot;">​</a></h2><p>La replicacion fisica envia WAL a replicas:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>primary -&gt; WAL stream -&gt; standby</span></span></code></pre></div><p>Las replicas reproducen cambios para mantenerse sincronizadas.</p><h2 id="restauracion-a-punto-en-el-tiempo" tabindex="-1">Restauracion a punto en el tiempo <a class="header-anchor" href="#restauracion-a-punto-en-el-tiempo" aria-label="Permalink to &quot;Restauracion a punto en el tiempo&quot;">​</a></h2><p>Necesitas:</p><ul><li>Backup base.</li><li>WAL archivado.</li><li>Objetivo de recuperacion.</li></ul><p>Ejemplo conceptual:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>restore backup base</span></span>
<span class="line"><span>replay WAL hasta 2026-06-26 10:30</span></span>
<span class="line"><span>abrir base recuperada</span></span></code></pre></div><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>No hagas backups sin WAL si necesitas PITR.</li><li>Monitoriza crecimiento de <code>pg_wal</code>.</li><li>Prueba recuperacion.</li><li>Vigila lag de replicas.</li><li>Usa herramientas de backup especializadas.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Borrar WAL manualmente.</li><li>Llenar disco por archiving roto.</li><li>Tener backup base sin WAL.</li><li>No probar restore.</li><li>Confundir replica con backup.</li></ul>`,27)])])}const k=e(t,[["render",r]]);export{u as __pageData,k as default};
